const express = require('express');
const app = express();

// Endpoint for completing levels
app.post('/levels', (req, res) => {
  // Get the level completion data from the request body
  const levelCompletionData = req.body;

  // Award rewards based on client-reported metrics
  if (levelCompletionData.score > 10 && levelCompletionData.time < 60) {
    res.json({ reward: 'coins', value: 5 });
  } else if (levelCompletionData.score > 20 && levelCompletionData.time < 30) {
    res.json({ reward: 'gems', value: 10 });
  } else {
    res.json({ reward: 'xp', value: 50 });
  }
});

// Endpoint for claiming rewards
app.post('/rewards', (req, res) => {
  // Get the reward data from the request body
  const rewardData = req.body;

  // Award the reward to the user
  res.json({ status: 'success' });
});

// Start the server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});